// 获取文档段落列表并提取编号信息
var doc = Application.ActiveDocument;
if (!doc) {
    return { error: "未找到活动文档，请先打开 Word 文档" };
}

var paragraphs = doc.Paragraphs;
var totalParagraphs = paragraphs.Count;

// 收集所有带编号的段落
var numberedItems = [];
for (var i = 1; i <= totalParagraphs; i++) {
    var para = paragraphs.Item(i);
    var text = para.Range.Text;
    // 去除末尾换行符
    text = text.replace(/\r\n?$/, '');

    // 匹配常见编号格式：1.、1.1、(1)、①等
    var numberPattern = /^(\d+([\.]\d+)*|[()]\d+[)]|[①②③④⑤⑥⑦⑧⑨⑩])\s*(.*)/;
    var match = text.match(numberPattern);

    if (match) {
        numberedItems.push({
            index: i,
            originalText: text,
            number: match[1],
            content: match[2] || ''
        });
    }
}

return {
    totalParagraphs: totalParagraphs,
    numberedCount: numberedItems.length,
    numberedItems: numberedItems.slice(0, 50) // 限制返回数量
};
